code = """import json

# Load repo languages
with open(locals()['var_function-call-8970436474990006304'], 'r') as f:
    repo_langs = json.load(f)

# Load READMEs
with open(locals()['var_function-call-15465379881174975645'], 'r') as f:
    readmes = json.load(f)

# Identify non-Python repos
non_python_repos = set()
all_known_repos = set()

for entry in repo_langs:
    repo = entry['repo_name']
    desc = entry['language_description']
    all_known_repos.add(repo)
    # Check if Python is mentioned. 
    # Note: "Python" could be part of a word like "IPython" (which is Python related). 
    # But usually the description lists languages: "Ruby", "Python", "Shell".
    # A simple substring check is probably sufficient given the format "includes: Python (...)" or "written in Python".
    if 'Python' not in desc:
        non_python_repos.add(repo)

# Count
numerator = 0
denominator = 0

for r in readmes:
    repo = r['sample_repo_name']
    
    # We only consider repos for which we have metadata. 
    # If a repo is in artifacts but not in metadata, we exclude it from the "Among repositories..." set.
    if repo in non_python_repos:
        denominator += 1
        content = r['content']
        # Check for copyright
        # Case insensitive check for "copyright" or presence of "©"
        if 'copyright' in content.lower() or '©' in content:
            numerator += 1

proportion = numerator / denominator if denominator > 0 else 0.0

result = {
    "numerator": numerator,
    "denominator": denominator,
    "proportion": proportion
}

print("__RESULT__:")
print(json.dumps(result))"""

